#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

static bool temperature_is_rising(int current_temp, int previous_temp)
{
    return (current_temp > previous_temp);
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        /* Check for stale sensor data (> 1000 ms timeout) */
        if ((controller->last_valid_sensor_ms > 0U) && 
            ((input.now_ms - controller->last_valid_sensor_ms) > CONTROLLER_SENSOR_TIMEOUT_MS)) {
            /* Stale sensor - fail safe */
            controller_set_safe_off(controller);
            output.timed_out = true;
        } else {
            /* Valid temperature received - apply control policy */
            controller->has_valid_sensor = true;
            controller->last_temperature_c = input.temperature_c;
            controller->last_valid_sensor_ms = input.now_ms;

            if (controller->last_temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
                /* Temp below lower threshold: heat up */
                controller_set_safe_off(controller);
                output.heater_on = true;
            } else if (controller->last_temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
                /* Temp above upper threshold: turn off heater */
                controller_set_safe_off(controller);
                output.timed_out = false;
            } else if (controller->last_temperature_c >= CONTROLLER_TEMP_LOW_THRESHOLD && 
                       controller->last_temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                /* Inside lower band [47, 50): preserve previous safe state */
                controller_set_safe_off(controller);
            } else if (controller->last_temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && 
                       controller->last_temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
                /* Near upper band [50, 52]: check if temperature is rising */
                bool temp_rising = temperature_is_rising(controller->last_temperature_c, controller->last_temperature_c);

                /* For the first valid reading or if previous temp is 0 (initial), treat as not rising */
                if (controller->last_temperature_c == 0) {
                    temp_rising = false;
                } else if (controller->state != CONTROLLER_STATE_HOLDING) {
                    temp_rising = false; /* Not yet in HOLDING state, default to preserving */
                }

                if (temp_rising) {
                    /* Temperature rising near upper band: early off with HOLDING state */
                    controller->heater_on = false;
                    controller->state = CONTROLLER_STATE_HOLDING;
                } else {
                    /* Not rising: preserve previous safe actuator state */
                    controller_set_safe_off(controller);
                }
            }
        }
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        /* Explicit sensor timeout - fail safe */
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        break;
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        /* Malformed input - fail safe */
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        break;
    case CONTROLLER_INPUT_NONE:
    default:
        /* No valid input - fail safe */
        controller_set_safe_off(controller);
        break;
    }

    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

    return output;
}

